// Mode: Run Once for All Items

const currentItem = $input.all()[0].json;
const pageId = String(currentItem.id);
const props = currentItem.properties;

const title = props['Job Title']?.title?.[0]?.plain_text || 'Not provided';
const company = props['Company']?.rich_text?.[0]?.plain_text || 'Not provided';
const location = props['Location']?.rich_text?.[0]?.plain_text || 'Not provided';
const desc = (props['Job Description']?.rich_text?.[0]?.plain_text || 'Not provided').slice(0, 1500);

// Pre-initialize result — this ALWAYS gets returned at the bottom
const result = {
  pageId: pageId,
  total_score: 0,
  verdict: 'Error',
  reason: 'Not scored yet',
  breakdown: 'Role: 0/35 | Location: 0/25 | Experience: 0/20 | Skills: 0/20'
};

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 300,
      system: 'Return ONLY a raw JSON object, no markdown. Score this job for Nibras, a CCNA-certified IT intern in Dubai. STRICT LIMITS: role_score max 35, location_score max 25, experience_score max 20, skills_score max 20. total_score = role_score + location_score + experience_score + skills_score. Format: {"total_score":0,"verdict":"Apply Now","role_score":0,"location_score":0,"experience_score":0,"skills_score":0,"reason":"one sentence"}. Verdicts: 80-100=Apply Now, 60-79=Good Fit, 40-59=Maybe, 0-39=Skip.',
      messages: [{ role: 'user', content: 'Score:\nTitle: ' + title + '\nCompany: ' + company + '\nLocation: ' + location + '\nDesc: ' + desc }]
    },
    json: true
  });

  const raw = String(response && response.content && response.content[0] ? response.content[0].text : '{}');
  const match = raw.match(/\{[\s\S]*\}/);

  if (match) {
    const p = JSON.parse(match[0]);
    result.total_score = Number(p.total_score) || 0;
    result.verdict = String(p.verdict || 'Error');
    result.reason = String(p.reason || 'No reason');
    result.breakdown = 'Role: ' + (Number(p.role_score)||0) + '/35 | Location: ' + (Number(p.location_score)||0) + '/25 | Experience: ' + (Number(p.experience_score)||0) + '/20 | Skills: ' + (Number(p.skills_score)||0) + '/20';
  } else {
    result.reason = 'Claude returned: ' + raw.slice(0, 100);
  }

} catch (e) {
  result.reason = 'Caught error: ' + String(e && e.message ? e.message : e).slice(0, 150);
}

// ALWAYS returned — never inside try/catch
return [{ json: result }];
